    cvss_descLow:        { de: 'Niedrig: Minimaler Schaden, schwer ausnutzbar oder starke einschränkende Faktoren vorhanden.', en: 'Low: minimal damage, difficult exploitation, or strong limiting factors.', fr: 'Faible : dommages minimes, exploitation difficile ou facteurs fortement limitants.', nl: 'Laag: minimale schade, moeilijk uit te buiten of sterke beperkende factoren.' },
